# ============================================================================
# SETTINGS MANAGEMENT
# ============================================================================

def load_settings():
    """Load settings from content storage, merged with defaults."""
    saved = load_content_json(CONTENT_SETTINGS, {})
    settings = dict(DEFAULT_SETTINGS)
    if saved.get('fiscal_year_start_month'):
        settings['fiscal_year_start_month'] = int(saved['fiscal_year_start_month'])
    if 'ag_grid_enterprise' in saved:
        settings['ag_grid_enterprise'] = bool(saved['ag_grid_enterprise'])
    if saved.get('ag_grid_license_key'):
        settings['ag_grid_license_key'] = str(saved['ag_grid_license_key'])
    if saved.get('category_roles'):
        cr = dict(DEFAULT_SETTINGS['category_roles'])
        cr.update(saved['category_roles'])
        settings['category_roles'] = cr
    # Contact tracking settings
    if 'contact_tracking' in saved:
        settings['contact_tracking'] = bool(saved['contact_tracking'])
    if 'contact_lookback_days' in saved:
        settings['contact_lookback_days'] = int(saved['contact_lookback_days'])
    if 'contact_methods' in saved:
        settings['contact_methods'] = saved['contact_methods']
    # Per-report role overrides
    if 'report_roles' in saved:
        settings['report_roles'] = saved['report_roles']
    # Engagement score weights
    if saved.get('engagement_weights'):
        ew = dict(DEFAULT_SETTINGS['engagement_weights'])
        for k, v in saved['engagement_weights'].items():
            if k in ew and isinstance(v, dict):
                ew[k] = {'enabled': bool(v.get('enabled', True)), 'weight': int(v.get('weight', ew[k]['weight']))}
        settings['engagement_weights'] = ew
    return settings

def save_settings(settings):
    """Save settings to content storage."""
    return save_content_json(CONTENT_SETTINGS, settings)

def user_has_category_access(category, settings):
    """Check if current user can access a category based on role settings."""
    roles = settings.get('category_roles', {}).get(category, [])
    if not roles:
        return True  # No role restriction = everyone can see it
    for role in roles:
        try:
            if model.UserIsInRole(role):
                return True
        except:
            pass
    return False

def user_has_report_access(report_id, category, settings):
    """Check if current user can access a specific report.
    First checks report-level roles, then falls back to category-level."""
    report_roles = settings.get('report_roles', {}).get(report_id, [])
    if report_roles:
        # Report has specific role restriction
        for role in report_roles:
            try:
                if model.UserIsInRole(role):
                    return True
            except:
                pass
        return False
    # No report-level restriction, fall back to category access
    return user_has_category_access(category, settings)

def is_admin_user():
    """Check if current user is Admin or Developer."""
    try:
        return model.UserIsInRole('Admin') or model.UserIsInRole('Developer')
    except:
        return False

# ============================================================================
# UNICODE / ENCODING HELPERS (IronPython 2.7 safe)
# ============================================================================

_LATIN_TO_ASCII = {
    0xc0: 'A', 0xc1: 'A', 0xc2: 'A', 0xc3: 'A', 0xc4: 'A', 0xc5: 'A',
    0xc6: 'AE', 0xc7: 'C', 0xc8: 'E', 0xc9: 'E', 0xca: 'E', 0xcb: 'E',
    0xcc: 'I', 0xcd: 'I', 0xce: 'I', 0xcf: 'I', 0xd0: 'D', 0xd1: 'N',
    0xd2: 'O', 0xd3: 'O', 0xd4: 'O', 0xd5: 'O', 0xd6: 'O', 0xd8: 'O',
    0xd9: 'U', 0xda: 'U', 0xdb: 'U', 0xdc: 'U', 0xdd: 'Y', 0xdf: 'ss',
    0xe0: 'a', 0xe1: 'a', 0xe2: 'a', 0xe3: 'a', 0xe4: 'a', 0xe5: 'a',
    0xe6: 'ae', 0xe7: 'c', 0xe8: 'e', 0xe9: 'e', 0xea: 'e', 0xeb: 'e',
    0xec: 'i', 0xed: 'i', 0xee: 'i', 0xef: 'i', 0xf0: 'd', 0xf1: 'n',
    0xf2: 'o', 0xf3: 'o', 0xf4: 'o', 0xf5: 'o', 0xf6: 'o', 0xf8: 'o',
    0xf9: 'u', 0xfa: 'u', 0xfb: 'u', 0xfc: 'u', 0xfd: 'y', 0xff: 'y',
    0x2018: "'", 0x2019: "'", 0x201c: '"', 0x201d: '"',
    0x2013: '-', 0x2014: '-', 0x2026: '...', 0xa0: ' ',
}

def _to_ascii(s):
    result = []
    for c in s:
        o = ord(c)
        if o < 128:
            result.append(c)
        else:
            result.append(_LATIN_TO_ASCII.get(o, '?'))
    return ''.join(result)

def safe_str(val):
    if val is None:
        return ''
    try:
        if isinstance(val, unicode):
            return _to_ascii(val)
    except NameError:
        pass
    try:
        return _to_ascii(unicode(val))
    except:
        pass
    try:
        s = str(val)
        try:
            return _to_ascii(s.decode('utf-8'))
        except:
            pass
        try:
            return _to_ascii(s.decode('latin-1'))
        except:
            pass
        return ''.join(c if ord(c) < 128 else '?' for c in s)
    except:
        pass
    try:
        return repr(val)
    except:
        return ''

def sanitize_for_json(obj):
    if obj is None:
        return None
    if isinstance(obj, bool):
        return obj
    if isinstance(obj, (int, float)):
        return obj
    try:
        if isinstance(obj, long):
            return obj
    except NameError:
        pass
    if isinstance(obj, dict):
        return {sanitize_for_json(k): sanitize_for_json(v) for k, v in obj.items()}
    if isinstance(obj, (list, tuple)):
        return [sanitize_for_json(item) for item in obj]
    return safe_str(obj)

# ============================================================================
# UTILITY FUNCTIONS
# ============================================================================

def html_escape(text):
    if not text:
        return ''
    s = safe_str(text)
    s = s.replace('&', '&amp;')
    s = s.replace('<', '&lt;')
    s = s.replace('>', '&gt;')
    s = s.replace('"', '&quot;')
    s = s.replace("'", '&#39;')
    return s

def safe_int(val, default=0):
    try:
        return int(val)
    except:
        return default

def safe_float(val, default=0.0):
    try:
        return float(val)
    except:
        return default

def fmt_currency(val):
    try:
        n = float(val)
        if n < 0:
            return '-${0:,.2f}'.format(abs(n))
        return '${0:,.2f}'.format(n)
    except:
        return '$0.00'

def fmt_number(val):
    try:
        n = float(val)
        if n == int(n):
            return '{0:,}'.format(int(n))
        return '{0:,.2f}'.format(n)
    except:
        return '0'

def fmt_pct(val):
    try:
        return '{0:.1f}%'.format(float(val))
    except:
        return '0.0%'

def fmt_date(dt):
    if not dt:
        return ''
    try:
        s = str(dt)
        if len(s) >= 10:
            return s[:10]
        return s
    except:
        return ''

def get_param(name, default=''):
    try:
        if hasattr(Data, name):
            v = getattr(Data, name)
            if v is not None:
                return str(v)
    except:
        pass
    return default

def load_content_json(name, default=None):
    if default is None:
        default = {}
    try:
        raw = model.TextContent(name)
        if raw:
            return json.loads(raw)
    except:
        pass
    return default

def save_content_json(name, obj):
    try:
        model.WriteContentText(name, json.dumps(sanitize_for_json(obj)), '')
        return True
    except:
        return False

