# BLUE TOOLBAR DETECTION
# ============================================================================

def detect_blue_toolbar():
    """Detect Blue Toolbar selection via @BlueToolbarTagId.
    Returns list of PeopleIds or empty list."""
    people_ids = []
    try:
        bt_sql = '''
            SELECT p.PeopleId
            FROM dbo.People p
            JOIN dbo.TagPerson tp ON tp.PeopleId = p.PeopleId
            WHERE tp.Id = @BlueToolbarTagId
        '''
        for r in q.QuerySql(bt_sql):
            people_ids.append(r.PeopleId)
    except:
        pass
    return people_ids

def get_bt_people_details(people_ids):
    """Get name details for Blue Toolbar people."""
    if not people_ids:
        return []
    pid_csv = ','.join(str(int(pid)) for pid in people_ids)
    details = []
    try:
        sql = '''
            SELECT TOP 50 p.PeopleId, p.Name2 as Name
            FROM People p
            WHERE p.PeopleId IN ({0})
            ORDER BY p.Name2
        '''.format(pid_csv)
        for r in q.QuerySql(sql):
            details.append({'id': r.PeopleId, 'name': safe_str(r.Name)})
    except:
        pass
    return details

# ============================================================================
# PARAMETER BUILDER - Builds WHERE clauses from report parameters
# ============================================================================

def build_where_clauses(params, filter_values, bt_people_ids=None, settings=None):
    """Build WHERE clause fragments from report parameters and submitted values.
    Returns a list of SQL fragments to AND together."""
    if settings is None:
        settings = DEFAULT_SETTINGS
    fiscal_month = settings.get('fiscal_year_start_month', 10)
    clauses = []

    for p in params:
        pname = p.get('name', '')
        ptype = p.get('type', '')
        col = p.get('sql_column', '')
        val = filter_values.get(pname, '')

        if not col or not val:
            continue

        if ptype == 'daterange':
            parts = val.split('|')
            if len(parts) == 2:
                start = parts[0].strip()
                end = parts[1].strip()
                if start and end:
                    clauses.append("{0} BETWEEN '{1}' AND '{2}'".format(
                        col, start.replace("'", ""), end.replace("'", "")))
            elif val == 'last_30_days':
                clauses.append("{0} >= DATEADD(day, -30, GETDATE())".format(col))
            elif val == 'last_90_days':
                clauses.append("{0} >= DATEADD(day, -90, GETDATE())".format(col))
            elif val == 'last_12_months':
                clauses.append("{0} >= DATEADD(month, -12, GETDATE())".format(col))
            elif val == 'last_6_months':
                clauses.append("{0} >= DATEADD(month, -6, GETDATE())".format(col))
            elif val == 'ytd':
                clauses.append("{0} >= DATEFROMPARTS(YEAR(GETDATE()), 1, 1)".format(col))
            elif val == 'fiscal_ytd':
                clauses.append(("{0} >= CASE WHEN MONTH(GETDATE()) >= {1} "
                    "THEN DATEFROMPARTS(YEAR(GETDATE()), {1}, 1) "
                    "ELSE DATEFROMPARTS(YEAR(GETDATE())-1, {1}, 1) END").format(col, fiscal_month))

        elif ptype == 'dropdown':
            safe_val = val.replace("'", "''")
            if safe_val.isdigit():
                clauses.append("{0} = {1}".format(col, safe_val))
            else:
                clauses.append("{0} = '{1}'".format(col, safe_val))

        elif ptype == 'multi_select':
            vals = [v.strip().replace("'", "''") for v in val.split(',') if v.strip()]
            if vals:
                if all(v.isdigit() for v in vals):
                    clauses.append("{0} IN ({1})".format(col, ','.join(vals)))
                else:
                    clauses.append("{0} IN ({1})".format(col,
                        ','.join("'" + v + "'" for v in vals)))

        elif ptype == 'number':
            op = p.get('operator', '>=')
            try:
                num = float(val)
                clauses.append("{0} {1} {2}".format(col, op, num))
            except:
                pass

        elif ptype == 'text':
            safe_val = val.replace("'", "''")
            clauses.append("{0} LIKE '%{1}%'".format(col, safe_val))

    # Blue Toolbar filter
    if bt_people_ids:
        pid_csv = ','.join(str(int(pid)) for pid in bt_people_ids)
        clauses.append("p.PeopleId IN ({0})".format(pid_csv))

    return clauses

