    # ---- ENGAGEMENT (continued - Lapsed Attendance Analysis) ----

    reports.append({
        'id': 'eng_lapsed_adults',
        'name': 'Lapsed Adults (Statistical)',
        'description': 'Adults (18+) whose current absence exceeds their normal pattern by 2+ standard deviations',
        'help_text': '<strong>Lapsed Adults (Statistical)</strong> uses statistical analysis to find adults 18+ whose current absence exceeds their normal attendance pattern by 2+ standard deviations. More sophisticated than a simple "hasn\'t attended in X days" — it accounts for each person\'s individual attendance rhythm.',
        'category': 'engagement',
        'icon': 'fa-user-clock',
        'sql_template': '''
            WITH AttendGaps AS (
                SELECT a.PeopleId, a.MeetingDate,
                    DATEDIFF(DAY, LAG(a.MeetingDate) OVER (PARTITION BY a.PeopleId ORDER BY a.MeetingDate), a.MeetingDate) AS gap_days
                FROM Attend a
                JOIN Organizations o ON a.OrganizationId = o.OrganizationId
                WHERE a.AttendanceFlag = 1
                    AND a.MeetingDate > DATEADD(MONTH, -12, GETDATE())
                    AND o.OrganizationStatusId = 30
            ),
            AttendStats AS (
                SELECT PeopleId,
                    COUNT(*) AS AttendCount,
                    CAST(AVG(CAST(gap_days AS FLOAT)) AS DECIMAL(5,1)) AS AvgGapDays,
                    CAST(STDEV(CAST(gap_days AS FLOAT)) AS DECIMAL(5,1)) AS StdDevGap,
                    MAX(MeetingDate) AS LastAttended,
                    DATEDIFF(DAY, MAX(MeetingDate), GETDATE()) AS DaysSinceLast
                FROM AttendGaps
                WHERE gap_days IS NOT NULL
                GROUP BY PeopleId
                HAVING COUNT(*) >= 2
                    AND STDEV(CAST(gap_days AS FLOAT)) BETWEEN 2 AND 5
            )
            SELECT
                p.PeopleId,
                p.Name2 AS Name,
                p.Age,
                p.EmailAddress AS Email,
                p.CellPhone AS Phone,
                s.AttendCount,
                s.AvgGapDays,
                s.DaysSinceLast,
                CAST((s.DaysSinceLast - s.AvgGapDays) / NULLIF(s.StdDevGap, 0) AS DECIMAL(4,1)) AS StdDevsOverdue,
                CONVERT(VARCHAR, s.LastAttended, 101) AS LastAttended
            FROM AttendStats s
            JOIN People p ON s.PeopleId = p.PeopleId
            WHERE p.IsDeceased = 0 AND p.ArchivedFlag = 0
                AND p.Age >= 18
                AND s.StdDevGap > 0
                AND (s.DaysSinceLast - s.AvgGapDays) / s.StdDevGap >= 2
                {filters}
            ORDER BY (s.DaysSinceLast - s.AvgGapDays) / s.StdDevGap DESC
        ''',
        'parameters': [],
        'display': {'types': ['table'], 'default': 'table'},
        'bluetoolbar': {'supported': True},
        'is_builtin': True
    })

    reports.append({
        'id': 'eng_lapsed_children',
        'name': 'Lapsed Children (Statistical)',
        'description': 'Children (under 18) whose current absence exceeds their normal pattern by 2+ standard deviations',
        'help_text': '<strong>Lapsed Children (Statistical)</strong> same statistical analysis as Lapsed Adults but for children under 18. Includes parent/guardian contact info since outreach would go to the parent.',
        'category': 'engagement',
        'icon': 'fa-child',
        'sql_template': '''
            WITH AttendGaps AS (
                SELECT a.PeopleId, a.MeetingDate,
                    DATEDIFF(DAY, LAG(a.MeetingDate) OVER (PARTITION BY a.PeopleId ORDER BY a.MeetingDate), a.MeetingDate) AS gap_days
                FROM Attend a
                JOIN Organizations o ON a.OrganizationId = o.OrganizationId
                WHERE a.AttendanceFlag = 1
                    AND a.MeetingDate > DATEADD(MONTH, -12, GETDATE())
                    AND o.OrganizationStatusId = 30
            ),
            AttendStats AS (
                SELECT PeopleId,
                    COUNT(*) AS AttendCount,
                    CAST(AVG(CAST(gap_days AS FLOAT)) AS DECIMAL(5,1)) AS AvgGapDays,
                    CAST(STDEV(CAST(gap_days AS FLOAT)) AS DECIMAL(5,1)) AS StdDevGap,
                    MAX(MeetingDate) AS LastAttended,
                    DATEDIFF(DAY, MAX(MeetingDate), GETDATE()) AS DaysSinceLast
                FROM AttendGaps
                WHERE gap_days IS NOT NULL
                GROUP BY PeopleId
                HAVING COUNT(*) >= 2
                    AND STDEV(CAST(gap_days AS FLOAT)) BETWEEN 2 AND 5
            )
            SELECT
                p.PeopleId,
                p.Name2 AS Name,
                p.Age,
                ISNULL(head.Name2, '') AS ParentName,
                ISNULL(head.CellPhone, '') AS ParentPhone,
                ISNULL(head.EmailAddress, '') AS ParentEmail,
                s.AttendCount,
                s.AvgGapDays,
                s.DaysSinceLast,
                CAST((s.DaysSinceLast - s.AvgGapDays) / NULLIF(s.StdDevGap, 0) AS DECIMAL(4,1)) AS StdDevsOverdue,
                CONVERT(VARCHAR, s.LastAttended, 101) AS LastAttended
            FROM AttendStats s
            JOIN People p ON s.PeopleId = p.PeopleId
            LEFT JOIN Families f ON p.FamilyId = f.FamilyId
            LEFT JOIN People head ON f.HeadOfHouseholdId = head.PeopleId
            WHERE p.IsDeceased = 0 AND p.ArchivedFlag = 0
                AND p.Age < 18 AND p.Age IS NOT NULL
                AND s.StdDevGap > 0
                AND (s.DaysSinceLast - s.AvgGapDays) / s.StdDevGap >= 2
                {filters}
            ORDER BY (s.DaysSinceLast - s.AvgGapDays) / s.StdDevGap DESC
        ''',
        'parameters': [],
        'display': {'types': ['table'], 'default': 'table'},
        'bluetoolbar': {'supported': True},
        'is_builtin': True
    })

    # ---- FINANCIAL (continued - Lapsed Giving) ----

    reports.append({
        'id': 'fin_lapsed_givers',
        'name': 'Lapsed Givers (Statistical)',
        'description': 'Givers whose current gap between gifts exceeds their normal pattern by 2+ standard deviations',
        'help_text': '<strong>Lapsed Givers</strong> uses statistical analysis to find people whose current gap between gifts is unusually long compared to their normal giving pattern (2+ standard deviations). Select people and create follow-up tasks directly.',
        'category': 'financial',
        'icon': 'fa-hand-holding-usd',
        'sql_template': '''
            WITH GivingDates AS (
                SELECT c.PeopleId,
                    CAST(c.ContributionDate AS DATE) AS GiftDate
                FROM Contribution c WITH (NOLOCK)
                WHERE c.ContributionTypeId NOT IN (6, 7, 8, 99)
                    AND c.ContributionStatusId = 0
                    AND c.ContributionDate >= DATEADD(year, -2, GETDATE())
                GROUP BY c.PeopleId, CAST(c.ContributionDate AS DATE)
            ),
            GivingLag AS (
                SELECT PeopleId, GiftDate,
                    LAG(GiftDate) OVER (PARTITION BY PeopleId ORDER BY GiftDate) AS PrevDate
                FROM GivingDates
            ),
            GivingGaps AS (
                SELECT PeopleId, GiftDate, PrevDate,
                    DATEDIFF(DAY, PrevDate, GiftDate) AS GapDays
                FROM GivingLag
                WHERE PrevDate IS NOT NULL
            ),
            GivingStats AS (
                SELECT PeopleId,
                    COUNT(*) AS GiftCount,
                    CAST(AVG(CAST(GapDays AS FLOAT)) AS DECIMAL(5,1)) AS AvgGapDays,
                    CAST(STDEV(CAST(GapDays AS FLOAT)) AS DECIMAL(5,1)) AS StdDevGap,
                    CONVERT(VARCHAR, MAX(GiftDate), 101) AS LastGift,
                    DATEDIFF(DAY, MAX(GiftDate), GETDATE()) AS DaysSinceLast
                FROM GivingGaps
                GROUP BY PeopleId
                HAVING COUNT(*) > 2
                    AND STDEV(CAST(GapDays AS FLOAT)) > 0
            )
            SELECT
                p.Name2 AS Name,
                s.LastGift,
                s.DaysSinceLast,
                s.GiftCount,
                s.AvgGapDays,
                p.EmailAddress AS Email,
                p.CellPhone AS Phone,
                CAST((s.DaysSinceLast - s.AvgGapDays) / NULLIF(s.StdDevGap, 0) AS DECIMAL(4,1)) AS StdDevsOverdue,
                p.PeopleId
            FROM GivingStats s
            JOIN People p ON s.PeopleId = p.PeopleId
            WHERE p.IsDeceased = 0 AND p.ArchivedFlag = 0
                AND s.StdDevGap > 0
                AND (s.DaysSinceLast - s.AvgGapDays) / s.StdDevGap >= 2
                {filters}
            ORDER BY (s.DaysSinceLast - s.AvgGapDays) / s.StdDevGap DESC
        ''',
        'parameters': [],
        'display': {'types': ['table'], 'default': 'table'},
        'bluetoolbar': {'supported': True},
        'is_builtin': True
    })

