def render_filter_panel(report_def):
    """Generate HTML for the dynamic filter panel."""
    params = report_def.get('parameters', [])
    if not params:
        return ''

    html = ['<div class="rb-filter-bar">']

    for p in params:
        pname = p.get('name', '')
        plabel = p.get('label', pname)
        ptype = p.get('type', '')
        pdefault = p.get('default', '')

        html.append('<div class="rb-filter-group">')
        html.append('<label>{0}</label>'.format(html_escape(plabel)))

        if ptype == 'daterange':
            html.append('<select name="filter_{0}" class="rb-filter-input rb-daterange-select" data-param="{0}">'.format(pname))
            presets = [
                ('last_30_days', 'Last 30 Days'), ('last_90_days', 'Last 90 Days'),
                ('last_6_months', 'Last 6 Months'), ('last_12_months', 'Last 12 Months'),
                ('ytd', 'Year to Date'), ('fiscal_ytd', 'Fiscal Year to Date'),
                ('custom', 'Custom Range...')
            ]
            for val, label in presets:
                sel = ' selected' if val == pdefault else ''
                html.append('<option value="{0}"{1}>{2}</option>'.format(val, sel, label))
            html.append('</select>')
            html.append('<div class="rb-custom-date-row" style="display:none;">')
            html.append('<input type="date" class="rb-filter-input rb-date-start" data-param="{0}_start" />'.format(pname))
            html.append('<span> to </span>')
            html.append('<input type="date" class="rb-filter-input rb-date-end" data-param="{0}_end" />'.format(pname))
            html.append('</div>')

        elif ptype == 'dropdown':
            source_sql = p.get('source_sql', '')
            static_options = p.get('options', [])
            html.append('<select name="filter_{0}" class="rb-filter-input" data-param="{0}">'.format(pname))
            if not static_options:
                html.append('<option value="">All</option>')
            if static_options:
                for opt in static_options:
                    sel = ' selected' if str(opt.get('value', '')) == str(p.get('default', '')) else ''
                    html.append('<option value="{0}"{2}>{1}</option>'.format(
                        html_escape(str(opt.get('value', ''))), html_escape(str(opt.get('label', ''))), sel))
            elif source_sql:
                try:
                    for r in q.QuerySql(source_sql):
                        v = safe_str(r.value)
                        l = safe_str(r.label)
                        html.append('<option value="{0}">{1}</option>'.format(html_escape(v), html_escape(l)))
                except:
                    pass
            html.append('</select>')

        elif ptype == 'multi_select':
            source_sql = p.get('source_sql', '')
            html.append('<select name="filter_{0}" class="rb-filter-input rb-multi-select" data-param="{0}" multiple style="min-height:80px;">'.format(pname))
            if source_sql:
                try:
                    for r in q.QuerySql(source_sql):
                        v = safe_str(r.value)
                        l = safe_str(r.label)
                        html.append('<option value="{0}">{1}</option>'.format(html_escape(v), html_escape(l)))
                except:
                    pass
            html.append('</select>')
            html.append('<div style="font-size:10px;color:#94a3b8;margin-top:2px;">Hold Ctrl/Cmd to select multiple</div>')

        elif ptype == 'text':
            html.append('<input type="text" class="rb-filter-input" data-param="{0}" placeholder="Search..." />'.format(pname))

        elif ptype == 'number':
            html.append('<input type="number" class="rb-filter-input" data-param="{0}" placeholder="0" />'.format(pname))

        html.append('</div>')

    html.append('<div class="rb-filter-group rb-filter-actions">')
    html.append('<button class="rb-btn rb-btn-primary" onclick="RB.runReport()"><i class="fas fa-play"></i> Run Report</button>')
    html.append('</div>')
    html.append('</div>')

    return ''.join(html)

# ============================================================================
# CUSTOM REPORT MANAGEMENT
# ============================================================================

def load_custom_reports(user_id):
    """Load custom reports: shared catalog + user-specific."""
    reports = []
    shared = load_content_json(CONTENT_CATALOG, {'reports': []})
    for r in shared.get('reports', []):
        r['is_builtin'] = False
        r['is_shared'] = True
        reports.append(r)
    user_reports = load_content_json(CONTENT_USER_PREFIX + str(user_id), {'reports': []})
    for r in user_reports.get('reports', []):
        r['is_builtin'] = False
        r['is_shared'] = False
        reports.append(r)
    return reports

def save_custom_report(user_id, report_def, shared=False):
    """Save a custom report definition."""
    if shared:
        catalog = load_content_json(CONTENT_CATALOG, {'reports': []})
        existing = [i for i, r in enumerate(catalog['reports']) if r.get('id') == report_def.get('id')]
        if existing:
            catalog['reports'][existing[0]] = report_def
        else:
            catalog['reports'].append(report_def)
        return save_content_json(CONTENT_CATALOG, catalog)
    else:
        key = CONTENT_USER_PREFIX + str(user_id)
        user_data = load_content_json(key, {'reports': []})
        existing = [i for i, r in enumerate(user_data['reports']) if r.get('id') == report_def.get('id')]
        if existing:
            user_data['reports'][existing[0]] = report_def
        else:
            user_data['reports'].append(report_def)
        return save_content_json(key, user_data)

def delete_custom_report(user_id, report_id, shared=False):
    """Delete a custom report."""
    if shared:
        catalog = load_content_json(CONTENT_CATALOG, {'reports': []})
        catalog['reports'] = [r for r in catalog['reports'] if r.get('id') != report_id]
        return save_content_json(CONTENT_CATALOG, catalog)
    else:
        key = CONTENT_USER_PREFIX + str(user_id)
        user_data = load_content_json(key, {'reports': []})
        user_data['reports'] = [r for r in user_data['reports'] if r.get('id') != report_id]
        return save_content_json(key, user_data)

# ============================================================================
# REPORT LOOKUP HELPERS
# ============================================================================

def get_all_reports(user_id, settings=None):
    """Get all reports: built-in + custom, filtered by role access."""
    if settings is None:
        settings = load_settings()
    all_reports = get_default_reports()
    all_reports.extend(load_custom_reports(user_id))
    # Filter by category + report-level role access
    visible = []
    for r in all_reports:
        cat = r.get('category', 'custom')
        rid = r.get('id', '')
        if user_has_report_access(rid, cat, settings):
            visible.append(r)
    return visible

def find_report(report_id, user_id):
    """Find a report by ID from built-in and custom reports."""
    for r in get_all_reports(user_id):
        if r.get('id') == report_id:
            return r
    return None

# ============================================================================
# AJAX HANDLER
# ============================================================================

def handle_ajax(action, user_id, bt_people_ids, current_org_id=None):
    """Handle AJAX requests. Returns JSON response string."""
    settings = load_settings()

    if action == 'run_report':
        report_id = get_param('report_id')
        display_type = get_param('display_type', 'table')
        report_def = find_report(report_id, user_id)
        if not report_def:
            return json.dumps({'success': False, 'error': 'Report not found: ' + report_id})

        # Role check: verify user can access this report's category
        cat = report_def.get('category', '')
        if not user_has_category_access(cat, settings):
            return json.dumps({'success': False, 'error': 'Access denied: you do not have permission for ' + cat + ' reports'})

        filter_values = {}
        for p in report_def.get('parameters', []):
            pname = p['name']
            ptype = p.get('type', '')
            val = get_param('filter_' + pname, '')
            if ptype == 'daterange' and val == 'custom':
                start = get_param('filter_' + pname + '_start', '')
                end = get_param('filter_' + pname + '_end', '')
                val = (start + '|' + end) if start and end else ''
            filter_values[pname] = val

        use_bt = bt_people_ids if report_def.get('bluetoolbar', {}).get('supported', False) else None
        # current_org_id is only honored when BT is supported AND active.
        # Without BT, the user is browsing reports normally and shouldn't
        # be silently scoped to an org they may have visited days ago.
        use_org = current_org_id if (use_bt and current_org_id) else None
        result = execute_report(report_def, filter_values, use_bt, settings,
                                current_org_id=use_org)

        if result.get('error'):
            return json.dumps(sanitize_for_json({'success': False, 'error': result['error']}))

        # Always include grid data for AG Grid rendering
        grid_data = render_grid_data(result, report_def)

        if display_type == 'chart':
            chart_json = render_chart_data_json(result, report_def)
            return json.dumps(sanitize_for_json({
                'success': True, 'display': 'chart',
                'chart_data': json.loads(chart_json),
                'row_count': result.get('row_count', 0),
                'grid_html': render_table_html(result, report_def),
                'grid_data': grid_data
            }))
        elif display_type == 'kpi':
            return json.dumps(sanitize_for_json({
                'success': True, 'display': 'kpi',
                'html': render_kpi_html(result, report_def),
                'row_count': result.get('row_count', 0),
                'grid_html': render_table_html(result, report_def),
                'grid_data': grid_data
            }))
        else:
            return json.dumps(sanitize_for_json({
                'success': True, 'display': 'table',
                'grid_html': render_table_html(result, report_def),
                'grid_data': grid_data,
                'row_count': result.get('row_count', 0)
            }))

    elif action == 'load_filters':
        report_id = get_param('report_id')
        report_def = find_report(report_id, user_id)
        if not report_def:
            return json.dumps({'success': False, 'error': 'Report not found'})
        display = report_def.get('display', {})
        return json.dumps(sanitize_for_json({
            'success': True,
            'filter_html': render_filter_panel(report_def),
            'display_types': display.get('types', ['table']),
            'default_display': display.get('default', 'table'),
            'report_name': report_def.get('name', ''),
            'report_desc': report_def.get('description', ''),
            'help_text': report_def.get('help_text', ''),
            'bt_supported': report_def.get('bluetoolbar', {}).get('supported', False)
        }))

    elif action == 'export_csv':
        report_id = get_param('report_id')
        report_def = find_report(report_id, user_id)
        if not report_def:
            return json.dumps({'success': False, 'error': 'Report not found'})

        filter_values = {}
        for p in report_def.get('parameters', []):
            pname = p['name']
            ptype = p.get('type', '')
            val = get_param('filter_' + pname, '')
            if ptype == 'daterange' and val == 'custom':
                start = get_param('filter_' + pname + '_start', '')
                end = get_param('filter_' + pname + '_end', '')
                val = (start + '|' + end) if start and end else ''
            filter_values[pname] = val

        use_bt = bt_people_ids if report_def.get('bluetoolbar', {}).get('supported', False) else None
        use_org = current_org_id if (use_bt and current_org_id) else None
        result = execute_report(report_def, filter_values, use_bt, settings,
                                current_org_id=use_org)
        csv_data = render_csv(result)
        return json.dumps(sanitize_for_json({
            'success': True, 'csv': csv_data,
            'filename': report_def.get('name', 'report').replace(' ', '_') + '.csv'
        }))

    elif action == 'save_report':
        report_json = get_param('report_json', '')
        is_shared = get_param('is_shared', 'false') == 'true'
        try:
            report_def = json.loads(report_json)
            if not report_def.get('id'):
                report_def['id'] = 'custom_' + str(int(
                    (datetime.datetime.now() - datetime.datetime(2000, 1, 1)).total_seconds()))
            report_def['is_builtin'] = False
            ok = save_custom_report(user_id, report_def, shared=is_shared)
            return json.dumps({'success': ok, 'report_id': report_def['id']})
        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

    elif action == 'delete_report':
        report_id = get_param('report_id')
        is_shared = get_param('is_shared', 'false') == 'true'
        ok = delete_custom_report(user_id, report_id, shared=is_shared)
        return json.dumps({'success': ok})

    elif action == 'validate_sql':
        sql_text = get_param('sql_text', '')
        if not sql_text:
            return json.dumps({'success': False, 'error': 'No SQL provided'})
        # Clean out template placeholders for validation
        clean_sql = sql_text.replace('{filters}', '').replace('{filters_where}', '').replace('{bluetoolbar_filter}', '')
        test_sql = 'SELECT TOP 1 * FROM ({0}) AS _test'.format(clean_sql)
        try:
            cols = []
            for r in q.QuerySql(test_sql):
                for attr in dir(r):
                    if not attr.startswith('_') and attr not in ('Count', 'Keys', 'Values', 'Items',
                        'GetType', 'ToString', 'Equals', 'GetHashCode', 'ReferenceEquals'):
                        try:
                            getattr(r, attr)
                            cols.append(attr)
                        except:
                            pass
                break
            return json.dumps(sanitize_for_json({'success': True, 'columns': cols}))
        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

    elif action == 'search_orgs':
        search_term = get_param('search_term', '')
        if not search_term or len(search_term) < 2:
            return json.dumps({'success': True, 'orgs': []})
        safe_term = search_term.replace("'", "''")
        try:
            sql = '''
                SELECT TOP 20
                    o.OrganizationId, o.OrganizationName,
                    d.Name AS DivisionName, p.Name AS ProgramName,
                    (SELECT COUNT(*) FROM OrganizationMembers om
                     WHERE om.OrganizationId = o.OrganizationId) AS MemberCount
                FROM Organizations o
                LEFT JOIN Division d ON o.DivisionId = d.Id
                LEFT JOIN Program p ON d.ProgId = p.Id
                WHERE o.OrganizationStatusId = 30
                    AND (o.OrganizationName LIKE '%{0}%'
                         OR CAST(o.OrganizationId AS VARCHAR) = '{0}')
                ORDER BY o.OrganizationName
            '''.format(safe_term)
            orgs = []
            for r in q.QuerySql(sql):
                orgs.append({
                    'id': r.OrganizationId,
                    'name': safe_str(r.OrganizationName),
                    'division': safe_str(r.DivisionName),
                    'program': safe_str(r.ProgramName),
                    'members': r.MemberCount or 0
                })
            return json.dumps(sanitize_for_json({'success': True, 'orgs': orgs}))
        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

    elif action == 'select_org':
        org_id = get_param('org_id', '')
        if not org_id:
            return json.dumps({'success': False, 'error': 'No org ID'})
        try:
            oid = int(org_id)
            sql = '''
                SELECT om.PeopleId
                FROM OrganizationMembers om
                WHERE om.OrganizationId = {0}
            '''.format(oid)
            pids = []
            for r in q.QuerySql(sql):
                pids.append(r.PeopleId)
            return json.dumps(sanitize_for_json({
                'success': True, 'people_ids': pids, 'count': len(pids)
            }))
        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

    elif action == 'get_settings':
        if not is_admin_user():
            return json.dumps({'success': False, 'error': 'Admin access required'})
        return json.dumps(sanitize_for_json({'success': True, 'settings': settings}))

    elif action == 'save_settings':
        if not is_admin_user():
            return json.dumps({'success': False, 'error': 'Admin access required'})
        try:
            new_fiscal = get_param('fiscal_month', '')
            new_roles_json = get_param('category_roles', '')
            new_ag_ent = get_param('ag_enterprise', '')
            new_ag_key = get_param('ag_license_key', '')
            updated = dict(settings)
            if new_fiscal:
                updated['fiscal_year_start_month'] = int(new_fiscal)
            if new_ag_ent:
                updated['ag_grid_enterprise'] = (new_ag_ent == 'true')
            updated['ag_grid_license_key'] = new_ag_key
            if new_roles_json:
                updated['category_roles'] = json.loads(new_roles_json)
            # Contact tracking settings
            ct_enabled = get_param('contact_tracking', '')
            ct_days = get_param('contact_lookback_days', '')
            ct_methods_json = get_param('contact_methods', '')
            if ct_enabled:
                updated['contact_tracking'] = (ct_enabled == 'true')
            if ct_days:
                updated['contact_lookback_days'] = int(ct_days)
            if ct_methods_json:
                updated['contact_methods'] = json.loads(ct_methods_json)
            # Per-report role overrides
            rr_json = get_param('report_roles', '')
            if rr_json:
                updated['report_roles'] = json.loads(rr_json)
            # Engagement weights
            ew_json = get_param('engagement_weights', '')
            if ew_json:
                updated['engagement_weights'] = json.loads(ew_json)
            ok = save_settings(updated)
            return json.dumps({'success': ok})
        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

    elif action == 'bulk_tag':
        pids_raw = get_param('people_ids', '')
        tag_name = get_param('tag_name', '')
        if not pids_raw or not tag_name:
            return json.dumps({'success': False, 'error': 'Missing people IDs or tag name'})
        try:
            pids = [int(p.strip()) for p in pids_raw.split(',') if p.strip()]
            pid_csv = ','.join(str(p) for p in pids)
            query_str = "peopleids='{0}'".format(pid_csv)
            current_user = model.UserPeopleId
            model.AddTag(query_str, tag_name, current_user, False)
            return json.dumps({'success': True, 'count': len(pids), 'message': 'Tagged {0} people with "{1}"'.format(len(pids), tag_name)})
        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

    elif action == 'bulk_task':
        pids_raw = get_param('people_ids', '')
        task_message = get_param('task_message', '')
        assignee_id_raw = get_param('assignee_id', '')
        due_date_raw = get_param('due_date', '')
        if not pids_raw or not task_message:
            return json.dumps({'success': False, 'error': 'Missing people IDs or message'})
        try:
            pids = [int(p.strip()) for p in pids_raw.split(',') if p.strip()]
            current_user = model.UserPeopleId
            assignee = int(assignee_id_raw) if assignee_id_raw else current_user
            due_date = model.ParseDate(due_date_raw) if due_date_raw else None
            success_count = 0
            for pid in pids:
                try:
                    model.CreateTaskNote(current_user, pid, assignee, None, False, task_message, '', due_date, [], True)
                    success_count += 1
                except:
                    pass
            return json.dumps({'success': True, 'count': success_count, 'message': 'Created {0} tasks'.format(success_count)})
        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

    elif action == 'bulk_note':
        pids_raw = get_param('people_ids', '')
        note_message = get_param('note_message', '')
        if not pids_raw or not note_message:
            return json.dumps({'success': False, 'error': 'Missing people IDs or message'})
        try:
            pids = [int(p.strip()) for p in pids_raw.split(',') if p.strip()]
            current_user = model.UserPeopleId
            success_count = 0
            for pid in pids:
                try:
                    model.CreateTaskNote(current_user, pid, current_user, None, True, '', note_message, None, [], False)
                    success_count += 1
                except:
                    pass
            return json.dumps({'success': True, 'count': success_count, 'message': 'Added {0} notes'.format(success_count)})
        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

    elif action == 'search_assignee':
        search_term = get_param('search_term', '')
        if not search_term or len(search_term) < 2:
            return json.dumps({'success': True, 'people': []})
        # Split search into words so "ben swaby" matches "Swaby, Ben"
        words = [w.strip().replace("'", "''") for w in search_term.split() if w.strip()]
        try:
            # Each word must match at least one of Name2, FirstName, LastName, NickName
            word_clauses = []
            for w in words:
                word_clauses.append("(p.Name2 LIKE '%{0}%' OR p.FirstName LIKE '%{0}%' OR p.LastName LIKE '%{0}%' OR p.NickName LIKE '%{0}%')".format(w))
            where = ' AND '.join(word_clauses) if word_clauses else '1=0'
            sql = '''
                SELECT TOP 10 p.PeopleId, p.Name2 AS Name, p.Age, p.EmailAddress
                FROM People p
                WHERE p.IsDeceased = 0 AND p.ArchivedFlag = 0
                    AND {0}
                ORDER BY p.Name2
            '''.format(where)
            people = []
            for r in q.QuerySql(sql):
                people.append({'id': r.PeopleId, 'name': safe_str(r.Name), 'age': r.Age if r.Age else None, 'email': safe_str(r.EmailAddress)})
            return json.dumps(sanitize_for_json({'success': True, 'people': people}))
        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

    elif action == 'get_keywords':
        try:
            kw_sql = "SELECT KeywordId, Description FROM dbo.Keyword WHERE IsActive = 1 ORDER BY Description"
            keywords = []
            for r in q.QuerySql(kw_sql):
                keywords.append({'keywordId': int(r.KeywordId), 'description': safe_str(r.Description)})
            return json.dumps(sanitize_for_json({'success': True, 'keywords': keywords}))
        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

    elif action == 'get_contact_methods':
        methods = settings.get('contact_methods', [])
        return json.dumps(sanitize_for_json({'success': True, 'methods': methods}))

    elif action == 'save_contact_methods':
        methods_json = get_param('methods_data', '[]')
        try:
            methods = json.loads(methods_json)
            updated = dict(settings)
            updated['contact_methods'] = methods
            save_settings(updated)
            return json.dumps({'success': True})
        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

    elif action == 'load_contact_efforts':
        pids_raw = get_param('people_ids', '')
        lookback = int(get_param('lookback_days', '90'))
        if not pids_raw:
            return json.dumps({'success': True, 'contactMap': {}})
        pids = [int(x.strip()) for x in pids_raw.split(',') if x.strip()]
        if not pids:
            return json.dumps({'success': True, 'contactMap': {}})
        pid_list = ','.join(str(p) for p in pids[:2000])  # Cap at 2000
        contact_map = {}
        try:
            # Load contact methods from Report Builder settings
            methods = settings.get('contact_methods', [])
            keyword_id_to_code = {}
            all_keyword_ids = []
            for m in methods:
                kid = m.get('keywordId')
                if kid:
                    keyword_id_to_code[int(kid)] = m.get('code', '?')
                    all_keyword_ids.append(int(kid))

            # Total TaskNote counts per person
            total_sql = """
                SELECT tn.AboutPersonId AS PeopleId,
                       COUNT(*) AS TotalCount,
                       DATEDIFF(day, MAX(tn.CreatedDate), GETDATE()) AS DaysSince,
                       CONVERT(VARCHAR, MAX(tn.CreatedDate), 101) AS LastContact
                FROM TaskNote tn WITH (NOLOCK)
                WHERE tn.AboutPersonId IN ({0})
                  AND tn.CreatedDate >= DATEADD(day, -{1}, GETDATE())
                GROUP BY tn.AboutPersonId
            """.format(pid_list, lookback)
            for r in q.QuerySql(total_sql):
                pid_key = str(r.PeopleId)
                contact_map[pid_key] = {
                    'total': int(r.TotalCount) if r.TotalCount else 0,
                    'daysSince': int(r.DaysSince) if r.DaysSince is not None else None,
                    'lastContact': safe_str(r.LastContact),
                    'methods': {}
                }

            # Per-keyword counts
            if all_keyword_ids and contact_map:
                contacted_pids = ','.join(contact_map.keys())
                kid_list = ','.join(str(k) for k in all_keyword_ids)
                method_sql = """
                    SELECT tn.AboutPersonId AS PeopleId, tnk.KeywordId, COUNT(*) AS Cnt
                    FROM TaskNote tn WITH (NOLOCK)
                    JOIN TaskNoteKeyword tnk ON tnk.TaskNoteId = tn.TaskNoteId
                    WHERE tn.AboutPersonId IN ({0})
                      AND tnk.KeywordId IN ({1})
                      AND tn.CreatedDate >= DATEADD(day, -{2}, GETDATE())
                    GROUP BY tn.AboutPersonId, tnk.KeywordId
                """.format(contacted_pids, kid_list, lookback)
                try:
                    for row in q.QuerySql(method_sql):
                        pid_key = str(row.PeopleId)
                        if pid_key in contact_map:
                            code = keyword_id_to_code.get(int(row.KeywordId), '')
                            if code:
                                contact_map[pid_key]['methods'][code] = int(row.Cnt) if row.Cnt else 0
                except:
                    pass

            # Build method codes list for JS
            method_codes = [{'code': m.get('code', ''), 'label': m.get('label', '')} for m in methods if m.get('code')]

            return json.dumps(sanitize_for_json({'success': True, 'contactMap': contact_map, 'methods': method_codes}))
        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

    elif action == 'apply_update':
        if not is_admin_user():
            return json.dumps({'success': False, 'error': 'Admin access required'})
        # Fetch code server-side using workers.dev URL (bypasses Cloudflare Bot Fight Mode)
        new_code = ''
        try:
            fetch_url = DC_API_WORKER + '/scripts/' + DC_SCRIPT_ID
            new_code = str(model.RestGet(fetch_url, {}))
        except Exception as fetch_err:
            return json.dumps({'success': False, 'error': 'Failed to fetch update: ' + safe_str(fetch_err)})
        if not new_code or len(new_code) < 100:
            return json.dumps({'success': False, 'error': 'Invalid or empty script code received'})
        try:
            # Detect script name: extract from URL path or use DC_SCRIPT_ID as fallback
            script_name = DC_SCRIPT_ID
            try:
                # Try to get from the current URL/context
                if hasattr(model, 'ScriptName') and model.ScriptName:
                    script_name = str(model.ScriptName)
                elif hasattr(model, 'URL') and model.URL:
                    import re as _re
                    url_str = str(model.URL)
                    m = _re.search(r'/PyScriptForm/(\w+)', url_str)
                    if not m:
                        m = _re.search(r'/PyScript/(\w+)', url_str)
                    if m:
                        script_name = m.group(1)
            except:
                pass
            model.WriteContentPython(script_name, new_code)
            return json.dumps({'success': True, 'message': 'Updated to latest version! Reload the page.'})
        except Exception as e:
            return json.dumps({'success': False, 'error': 'Write failed: ' + safe_str(e)})

    elif action == 'load_person_detail':
        pid = int(get_param('people_id', '0'))
        if pid <= 0:
            return json.dumps({'success': False, 'error': 'Invalid PeopleId'})
        detail = {'profile': {}, 'family': [], 'involvements': [], 'pastInvolvements': [], 'milestones': [], 'engagement': None, 'journeyEvents': []}
        try:
            # Profile + milestones
            prof_sql = """
                SELECT p.PeopleId, p.FamilyId, p.Name2, p.FirstName, p.LastName,
                       p.EmailAddress, p.CellPhone, p.HomePhone, p.WorkPhone,
                       p.Age, p.PrimaryAddress, p.PrimaryCity, p.PrimaryState, p.PrimaryZip,
                       p.EmployerOther, p.OccupationOther, p.SchoolOther,
                       g.Description as Gender, ms.Description as MemberStatus,
                       mar.Description as MaritalStatus, c.Description as CampusName,
                       CONVERT(VARCHAR(10), p.BDate, 120) as BirthDate,
                       CONVERT(VARCHAR(10), p.JoinDate, 120) as JoinDate,
                       CONVERT(VARCHAR(10), p.BaptismDate, 120) as BaptismDate,
                       CONVERT(VARCHAR(10), p.WeddingDate, 120) as WeddingDate,
                       CONVERT(VARCHAR(10), p.NewMemberClassDate, 120) as NewMemberClassDate,
                       CONVERT(VARCHAR(10), p.DropDate, 120) as DropDate,
                       CONVERT(VARCHAR(10), p.CreatedDate, 120) as RecordCreated,
                       dt.Description as DecisionType,
                       CONVERT(VARCHAR(10), p.DecisionDate, 120) as DecisionDate,
                       pic.MediumUrl as MediumPhoto, pic.SmallUrl as SmallPhoto, pic.LargeUrl as LargePhoto
                FROM People p
                LEFT JOIN lookup.Gender g ON p.GenderId = g.Id
                LEFT JOIN lookup.MemberStatus ms ON p.MemberStatusId = ms.Id
                LEFT JOIN lookup.MaritalStatus mar ON p.MaritalStatusId = mar.Id
                LEFT JOIN lookup.Campus c ON p.CampusId = c.Id
                LEFT JOIN lookup.DecisionType dt ON p.DecisionTypeId = dt.Id
                LEFT JOIN Picture pic ON p.PictureId = pic.PictureId
                WHERE p.PeopleId = {0}
            """.format(pid)
            fam_id = None
            for r in q.QuerySql(prof_sql):
                fam_id = r.FamilyId
                addr_parts = [safe_str(r.PrimaryAddress), safe_str(r.PrimaryCity), safe_str(r.PrimaryState), safe_str(r.PrimaryZip)]
                addr = ', '.join([p for p in addr_parts if p and p.strip()])
                detail['profile'] = {
                    'name': safe_str(r.Name2), 'firstName': safe_str(r.FirstName), 'lastName': safe_str(r.LastName),
                    'email': safe_str(r.EmailAddress), 'cellPhone': safe_str(r.CellPhone),
                    'homePhone': safe_str(r.HomePhone), 'workPhone': safe_str(r.WorkPhone),
                    'age': r.Age if r.Age else None, 'gender': safe_str(r.Gender),
                    'memberStatus': safe_str(r.MemberStatus), 'maritalStatus': safe_str(r.MaritalStatus),
                    'campus': safe_str(r.CampusName), 'address': addr,
                    'employer': safe_str(r.EmployerOther), 'occupation': safe_str(r.OccupationOther),
                    'school': safe_str(r.SchoolOther),
                    'photo': safe_str(r.MediumPhoto) if r.MediumPhoto else (safe_str(r.SmallPhoto) if r.SmallPhoto else ''),
                    'largePhoto': safe_str(r.LargePhoto) if r.LargePhoto else '',
                }
                milestones = []
                if r.BirthDate: milestones.append({'label': 'Birth Date', 'date': safe_str(r.BirthDate), 'icon': '&#127874;'})
                if r.RecordCreated: milestones.append({'label': 'Record Created', 'date': safe_str(r.RecordCreated), 'icon': '&#128221;'})
                if r.DecisionDate: milestones.append({'label': safe_str(r.DecisionType) if r.DecisionType else 'Decision', 'date': safe_str(r.DecisionDate), 'icon': '&#10013;'})
                if r.BaptismDate: milestones.append({'label': 'Baptism', 'date': safe_str(r.BaptismDate), 'icon': '&#128167;'})
                if r.NewMemberClassDate: milestones.append({'label': 'New Member Class', 'date': safe_str(r.NewMemberClassDate), 'icon': '&#127891;'})
                if r.JoinDate: milestones.append({'label': 'Joined Church', 'date': safe_str(r.JoinDate), 'icon': '&#127969;'})
                if r.WeddingDate: milestones.append({'label': 'Wedding', 'date': safe_str(r.WeddingDate), 'icon': '&#128141;'})
                if r.DropDate: milestones.append({'label': 'Dropped', 'date': safe_str(r.DropDate), 'icon': '&#128308;'})
                detail['milestones'] = milestones

            # Family members
            if fam_id:
                fam_sql = """
                    SELECT p.PeopleId, p.Name2, p.Age, p.PositionInFamilyId,
                           p.EmailAddress, p.CellPhone, ms.Description as MemberStatus,
                           pic.SmallUrl as PhotoUrl
                    FROM People p
                    LEFT JOIN lookup.MemberStatus ms ON p.MemberStatusId = ms.Id
                    LEFT JOIN Picture pic ON p.PictureId = pic.PictureId
                    WHERE p.FamilyId = {0} AND p.IsDeceased = 0 AND p.PeopleId != {1}
                    ORDER BY p.PositionInFamilyId
                """.format(fam_id, pid)
                pos_map = {10: 'Adult', 20: 'Adult', 30: 'Child'}
                for r in q.QuerySql(fam_sql):
                    detail['family'].append({
                        'pid': r.PeopleId, 'name': safe_str(r.Name2), 'age': r.Age if r.Age else None,
                        'position': pos_map.get(r.PositionInFamilyId, 'Other'),
                        'status': safe_str(r.MemberStatus), 'phone': safe_str(r.CellPhone),
                        'email': safe_str(r.EmailAddress), 'photo': safe_str(r.PhotoUrl) if r.PhotoUrl else '',
                    })

            # Current involvements with attendance
            inv_sql = """
                SELECT om.OrganizationId, o.OrganizationName, mt.Description as MemberType,
                       p.Name as ProgramName, CONVERT(VARCHAR(10), om.EnrollmentDate, 120) as EnrollDate,
                       (SELECT COUNT(*) FROM Attend a JOIN Meetings m ON a.MeetingId = m.MeetingId
                        WHERE a.PeopleId = {0} AND a.OrganizationId = om.OrganizationId
                        AND a.AttendanceFlag = 1 AND m.MeetingDate >= DATEADD(day, -90, GETDATE())) as Attend90,
                       (SELECT CONVERT(VARCHAR(10), MAX(m2.MeetingDate), 120) FROM Attend a2
                        JOIN Meetings m2 ON a2.MeetingId = m2.MeetingId
                        WHERE a2.PeopleId = {0} AND a2.OrganizationId = om.OrganizationId
                        AND a2.AttendanceFlag = 1) as LastAttend
                FROM OrganizationMembers om
                JOIN Organizations o ON o.OrganizationId = om.OrganizationId
                LEFT JOIN lookup.MemberType mt ON om.MemberTypeId = mt.Id
                LEFT JOIN Division d ON o.DivisionId = d.Id
                LEFT JOIN Program p ON d.ProgId = p.Id
                WHERE om.PeopleId = {0} AND o.OrganizationStatusId = 30
                ORDER BY p.Name, o.OrganizationName
            """.format(pid)
            for r in q.QuerySql(inv_sql):
                detail['involvements'].append({
                    'orgId': r.OrganizationId, 'name': safe_str(r.OrganizationName),
                    'memberType': safe_str(r.MemberType), 'program': safe_str(r.ProgramName),
                    'enrollDate': safe_str(r.EnrollDate), 'attend90': int(r.Attend90) if r.Attend90 else 0,
                    'lastAttend': safe_str(r.LastAttend),
                })

            # Engagement stats (configurable weighted scoring)
            try:
                eng_sql = """
                    SELECT
                        (SELECT COUNT(*) FROM Attend a WHERE a.PeopleId = {0} AND a.AttendanceFlag = 1
                         AND a.MeetingDate >= DATEADD(day, -90, GETDATE())) AS Attend90,
                        (SELECT DATEDIFF(day, MAX(a.MeetingDate), GETDATE())
                         FROM Attend a WHERE a.PeopleId = {0} AND a.AttendanceFlag = 1) AS DaysSince,
                        (SELECT COUNT(DISTINCT om.OrganizationId) FROM OrganizationMembers om
                         JOIN Organizations o ON om.OrganizationId = o.OrganizationId
                         WHERE om.PeopleId = {0} AND om.MemberTypeId IN (140, 310, 320, 710)
                         AND o.OrganizationStatusId = 30 AND om.InactiveDate IS NULL) AS ServingCount,
                        (SELECT COUNT(DISTINCT om.OrganizationId) FROM OrganizationMembers om
                         JOIN Organizations o ON om.OrganizationId = o.OrganizationId
                         WHERE om.PeopleId = {0} AND o.OrganizationStatusId = 30
                         AND om.InactiveDate IS NULL) AS GroupCount,
                        (SELECT TOP 1 CONVERT(varchar, a.MeetingDate, 101) + ' - ' + o.OrganizationName
                         FROM Attend a JOIN Organizations o ON a.OrganizationId = o.OrganizationId
                         WHERE a.PeopleId = {0} AND a.AttendanceFlag = 1
                         ORDER BY a.MeetingDate DESC) AS LastAttendance
                """.format(pid)
                eng = q.QuerySqlTop1(eng_sql)
                if eng:
                    a90 = int(eng.Attend90) if eng.Attend90 else 0
                    ds = int(eng.DaysSince) if eng.DaysSince is not None else None
                    srv = int(eng.ServingCount) if eng.ServingCount else 0
                    grp = int(eng.GroupCount) if eng.GroupCount else 0

                    # Score each factor 0-100
                    def _score_recency(d):
                        if d is None: return 0
                        if d <= 7: return 100
                        if d <= 14: return 85
                        if d <= 30: return 70
                        if d <= 60: return 40
                        if d <= 90: return 20
                        return 5
                    def _score_frequency(n):
                        if n >= 10: return 100
                        if n >= 7: return 80
                        if n >= 4: return 60
                        if n >= 2: return 40
                        if n >= 1: return 20
                        return 0
                    def _score_groups(n):
                        if n >= 4: return 100
                        if n >= 3: return 80
                        if n >= 2: return 60
                        if n >= 1: return 40
                        return 0
                    def _score_serving(n):
                        if n >= 3: return 100
                        if n >= 2: return 80
                        if n >= 1: return 60
                        return 0

                    factor_scores = {
                        'attend_recency': _score_recency(ds),
                        'attend_frequency': _score_frequency(a90),
                        'group_involvement': _score_groups(grp),
                        'serving': _score_serving(srv),
                    }

                    # Apply configurable weights
                    ew = settings.get('engagement_weights', DEFAULT_SETTINGS['engagement_weights'])
                    total_weight = 0
                    weighted_sum = 0
                    factor_detail = {}
                    for fk, fs in factor_scores.items():
                        fd = ew.get(fk, {'enabled': True, 'weight': 20})
                        if fd.get('enabled', True):
                            w = fd.get('weight', 20)
                            total_weight += w
                            weighted_sum += fs * w
                            factor_detail[fk] = {'score': fs, 'weight': w}
                        else:
                            factor_detail[fk] = {'score': fs, 'weight': 0, 'disabled': True}

                    score = int(round(weighted_sum / total_weight)) if total_weight > 0 else 0
                    score = max(0, min(100, score))

                    if ds is not None and ds <= 30: status = 'Active'
                    elif ds is not None and ds > 90: status = 'Inactive'
                    else: status = 'Occasional'

                    detail['engagement'] = {
                        'score': score, 'status': status, 'attend90': a90,
                        'daysSince': ds, 'servingCount': srv, 'groupCount': grp,
                        'lastAttendance': safe_str(eng.LastAttendance) if eng.LastAttendance else None,
                        'factors': factor_detail,
                    }
            except:
                pass

            # Journey timeline
            try:
                j_sql = """
                    SELECT p.CreatedDate AS EventDate, 'Added to System' AS EventType, 'system' AS Category
                    FROM People p WHERE p.PeopleId = {0}
                    UNION ALL
                    SELECT TOP 1 a.MeetingDate, 'First Attendance', 'attendance'
                    FROM Attend a WHERE a.PeopleId = {0} AND a.AttendanceFlag = 1
                    ORDER BY a.MeetingDate
                """.format(pid)
                for r in q.QuerySql(j_sql):
                    if r.EventDate:
                        detail['journeyEvents'].append({
                            'date': safe_str(r.EventDate).split(' ')[0],
                            'event': safe_str(r.EventType), 'type': safe_str(r.Category),
                        })
                detail['journeyEvents'].sort(key=lambda x: x.get('date', ''))
            except:
                pass

        except Exception as e:
            return json.dumps({'success': False, 'error': safe_str(e)})

        return json.dumps({'success': True, 'detail': detail})

    return json.dumps({'success': False, 'error': 'Unknown action: ' + action})

