    html.append('<div id="rb-display-toggle" class="rb-display-toggle"></div>')
    html.append('</div></div>')

    # Scope bar: org search (standalone) or BT indicator
    has_sel = ' has-selection' if bt_count > 0 else ''
    html.append('<div id="rb-scope-bar" class="rb-filter-scope{0}">'.format(has_sel))
