    if bt_count > 0:
        # Blue Toolbar active - show chip, hide search
        html.append('<span id="rb-scope-chip" class="rb-scope-chip" style="display:inline-flex">')
        html.append('<i class="fas fa-hand-pointer"></i> Blue Toolbar')
